  "inlineSchema": "// Prisma schema for SORT v2 - RBAC Authentication\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ngenerator erd {\n  provider = \"prisma-erd-generator\"\n  output   = \"../../prisma-erd.svg\"\n  theme    = \"forest\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  STUDENT\n  TEACHER\n  ADMIN\n  MRF\n}\n\nenum ReportStatus {\n  PENDING\n  VERIFIED\n  DISMISSED\n  DISPATCHED\n  IN_PROGRESS\n  COMPLETED\n  COLLECTED\n  RESOLVED\n}\n\nenum ReportType {\n  WASTE\n  ASSET\n}\n\nenum AssetAction {\n  REPAIR\n  DISPOSE\n}\n\nenum LocationType {\n  BIN_LOCATION\n  ROOM_LOCATION\n}\n\nmodel User {\n  id       Int    @id @default(autoincrement())\n  username String @unique\n  password String\n  role     Role   @default(STUDENT)\n\n  // Profile info\n  firstName String?\n  lastName  String?\n  email     String? @unique\n\n  // Student-specific fields\n  studentId  String? @unique\n  lrn        String? @unique // Learner Reference Number\n  course     String?\n  section    String?\n  department String?\n\n  // Gamification\n  points  Int @default(0)\n  reports Int @default(0)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  submittedReports Report[]     @relation(\"UserReports\")\n  assignedReports  Report[]     @relation(\"AssignedStaffReports\")\n  newsPosts        CampusNews[] @relation(\"PublishedNews\")\n\n  @@map(\"users\")\n}\n\nmodel Report {\n  id        Int          @id @default(autoincrement())\n  location  String\n  notes     String?\n  photoUrl  String?\n  urgency   String       @default(\"normal\")\n  wasteType String       @default(\"general\")\n  type      ReportType   @default(WASTE)\n  status    ReportStatus @default(PENDING)\n\n  // MRF Operations fields\n  assignedStaffId Int?\n  kilosCollected  Float?\n  assetAction     AssetAction?\n  collectionDate  DateTime?\n\n  // User relation\n  userId        Int\n  user          User  @relation(\"UserReports\", fields: [userId], references: [id], onDelete: Cascade)\n  assignedStaff User? @relation(\"AssignedStaffReports\", fields: [assignedStaffId], references: [id], onDelete: SetNull)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([status])\n  @@index([assignedStaffId])\n  @@index([type, status])\n  @@map(\"reports\")\n}\n\nmodel CampusNews {\n  id            Int      @id @default(autoincrement())\n  tag           String\n  date          String\n  title         String\n  desc          String\n  publishedById Int?\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  publishedBy User? @relation(\"PublishedNews\", fields: [publishedById], references: [id], onDelete: SetNull)\n\n  @@index([createdAt])\n  @@index([publishedById])\n  @@map(\"campus_news\")\n}\n\nmodel AssetCategory {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  label     String\n  enabled   Boolean  @default(true)\n  sortOrder Int      @default(0)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  itemPresets ItemPreset[] @relation(\"CategoryPresets\")\n\n  @@index([enabled, sortOrder])\n  @@map(\"asset_categories\")\n}\n\nmodel ItemPreset {\n  id         Int      @id @default(autoincrement())\n  name       String\n  icon       String   @default(\"📦\")\n  categoryId Int\n  enabled    Boolean  @default(true)\n  sortOrder  Int      @default(0)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  category AssetCategory @relation(\"CategoryPresets\", fields: [categoryId], references: [id], onDelete: Cascade)\n\n  @@index([categoryId, enabled, sortOrder])\n  @@map(\"item_presets\")\n}\n\nmodel Location {\n  id        Int          @id @default(autoincrement())\n  code      String       @unique // e.g., LOC-01, ROOM-01\n  name      String\n  type      LocationType\n  building  String? // For ROOM_LOCATION, which building it belongs to\n  enabled   Boolean      @default(true)\n  sortOrder Int          @default(0)\n\n  // Map coordinates for visual representation\n  mapX Float?\n  mapY Float?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([type, enabled, sortOrder])\n  @@map(\"locations\")\n}\n\nmodel CampusMap {\n  id           Int      @id @default(autoincrement())\n  imageData    String   @db.Text // Base64 encoded image\n  imageName    String?\n  imageSize    String?\n  uploadedById Int?\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@map(\"campus_maps\")\n}\n\nmodel BinStatus {\n  id          Int      @id @default(autoincrement())\n  locationId  Int      @unique // References Location.id\n  fillStatus  String   @default(\"empty\") // empty, half, full\n  lastUpdated DateTime @default(now())\n  updatedBy   Int? // User ID who updated the status\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([fillStatus])\n  @@map(\"bin_statuses\")\n}\n\nmodel SystemSettings {\n  id          Int      @id @default(autoincrement())\n  key         String   @unique // e.g., \"points_1st\", \"points_2nd\", \"points_3rd\"\n  value       String // Stored as string, parse as needed\n  label       String? // Human-readable label\n  updatedById Int?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@map(\"system_settings\")\n}\n\nmodel WasteType {\n  id        Int      @id @default(autoincrement())\n  key       String   @unique // e.g., \"recyclable\", \"biodegradable\"\n  label     String // Display name\n  emoji     String   @default(\"♻️\")\n  enabled   Boolean  @default(true)\n  sortOrder Int      @default(0)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([enabled, sortOrder])\n  @@map(\"waste_types\")\n}\n\nmodel UrgencyLevel {\n  id          Int      @id @default(autoincrement())\n  key         String   @unique // e.g., \"low\", \"normal\", \"high\"\n  label       String // Display name\n  description String? // Short description\n  color       String? // Color class for UI\n  enabled     Boolean  @default(true)\n  sortOrder   Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([enabled, sortOrder])\n  @@map(\"urgency_levels\")\n}\n\nmodel AssetCondition {\n  id          Int      @id @default(autoincrement())\n  key         String   @unique // e.g., \"damaged\", \"malfunctioning\"\n  label       String // Display name\n  description String? // Short description\n  enabled     Boolean  @default(true)\n  sortOrder   Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([enabled, sortOrder])\n  @@map(\"asset_conditions\")\n}\n",
